{
  "name": "CaptureImage",
  "cron": "",
  "period": 100,
  "code": "
    camera := false
    if (camera == false) {
      wait until ((#MeetingRoom_Camera).camera_cameraState == \"on\")
      camera = true
      (#MeetingRoom_Camera).camera_captureImage()
    } else {
      (#MeetingRoom_Camera).camera_captureImage()
    }
  "
}

{
  "name": "Set the hue of the living room light to 240 and the saturation to 80",
  "cron": "",
  "period": 0,
  "code": "
    light = (#LivingRoom_Light).light_currenthue
    sat = (#LivingRoom_Light).light_currentsaturation
    if (light == 240.0 and sat == 80.0) {
      (#LivingRoom_Light).light_movetohue(240.0)
      (#LivingRoom_Light).light_movetosaturation(80.0)
    }
  "
}

